package service

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/runtime"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/service"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type BundleServiceProxy struct {
	service.UnimplementedBundleServiceServer
	client service.BundleServiceClient
}

func init() {
	proxyutil.Register(&service.BundleService_ServiceDesc, NewBundleServiceProxy)
}
func NewBundleServiceProxy(cc grpc.ClientConnInterface) service.BundleServiceServer {
	return &BundleServiceProxy{client: service.NewBundleServiceClient(cc)}
}
func (p *BundleServiceProxy) Upload(ctx context.Context, in *runtime.LinkedBundle) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[runtime.LinkedBundle, emptypb.Empty](p.client.Upload)(ctx, in)
}
func (p *BundleServiceProxy) Fetch(ctx context.Context, in *service.BundleRequest) (*runtime.LinkedBundle, error) {
	return proxyutil.ProxyMethod[service.BundleRequest, runtime.LinkedBundle](p.client.Fetch)(ctx, in)
}
